 18→// Ordered list of themes for sidebar rendering. Only themes with fields are shown.
 19→export const THEME_ORDER: Theme[] = [
 20→  'CORE',
 21→  'LOCATION',
 22→  'ACADEMICS',
 23→  'COST',
 24→  'OUTCOMES',
 25→  'RANKING',
 26→  'ADMISSIONS',
 27→  'ATHLETICS',
 28→  'FIELDS_OF_STUDY',
 29→  'CULTURAL_ENVIRONMENT',
 30→  'WEATHER',
 31→]
 32→
 33→export const THEME_LABELS: Record<Theme, string> = {
 34→  CORE: 'Core',
 35→  LOCATION: 'Location',
 36→  ACADEMICS: 'Academics',
 37→  COST: 'Cost & Financial Aid',
 38→  OUTCOMES: 'Outcomes',
 39→  RANKING: 'Rankings',
 40→  ADMISSIONS: 'Admissions',
 41→  ATHLETICS: 'Athletics',
 42→  FIELDS_OF_STUDY: 'Fields of Study',
 43→  CULTURAL_ENVIRONMENT: 'Cultural Environment',
 44→  WEATHER: 'Weather & Climate',
 45→  PHYSICAL_ENVIRONMENT: 'Physical Environment',
 46→  DEMOGRAPHICS: 'Demographics',
 47→  REPUTATION: 'Reputation',
 48→  SAFETY: 'Safety',
 49→  STUDENT_LIFE: 'Student Life',
 50→  METADATA: 'Metadata',
 51→  OTHER: 'Other',
 52→}
 53→
 54→export interface ThemeGroup {
 55→  theme: Theme
 56→  label: string
 57→  fields: SearchField[]
 58→}
 59→
 60→export function fieldsByTheme(fields: SearchField[]): ThemeGroup[] {
 61→  // Group fields by theme
 62→  const grouped = new Map<Theme, SearchField[]>()
 63→  for (const f of fields) {
 64→    const existing = grouped.get(f.theme)
 65→    if (existing) {
 66→      existing.push(f)
 67→    } else {
 68→      grouped.set(f.theme, [f])
 69→    }
 70→  }
 71→
 72→  // Sort fields within each group alphabetically by label
 73→  for (const group of grouped.values()) {
 74→    group.sort((a, b) => a.label.localeCompare(b.label))
 75→  }
 76→
 77→  // Build ordered result: known themes first, then any unknown themes
 78→  const result: ThemeGroup[] = []
 79→  for (const theme of THEME_ORDER) {
 80→    const group = grouped.get(theme)
 81→    if (group && group.length > 0) {
 82→      result.push({ theme, label: THEME_LABELS[theme], fields: group })
 83→      grouped.delete(theme)
 84→    }
 85→  }
 86→  // Append any remaining themes not in THEME_ORDER
 87→  for (const [theme, group] of grouped) {
 88→    if (group.length > 0) {
 89→      result.push({ theme, label: THEME_LABELS[theme] ?? String(theme), fields: group })
 90→    }
 91→  }
 92→
 93→  return result
 94→}
