 96→const MILES_TO_KM = 1.60934
 97→
 98→export function buildFilterInputs(
 99→  filters: Record<string, unknown>,
100→): Array<{ field: string; value: unknown }> {
101→  return Object.entries(filters).map(([field, value]) => {
102→    if (
103→      typeof value === 'object' &&
104→      value !== null &&
105→      'latitude' in value &&
106→      'longitude' in value &&
107→      'radiusMiles' in value
108→    ) {
109→      const v = value as { latitude: number; longitude: number; radiusMiles: number }
110→      return {
111→        field,
112→        value: {
113→          kind: 'radius',
114→          radius: { lat: v.latitude, lng: v.longitude, radius_km: v.radiusMiles * MILES_TO_KM },
115→        },
116→      }
117→    }
118→    return { field, value }
119→  })
120→}
121→
122→export function serializeFilterValue(value: unknown): string {
123→  if (typeof value === 'object' && value !== null) {
124→    if ('query' in value) return String((value as { query: string }).query)
125→    if ('value' in value) return String((value as { value: string }).value)
126→    if ('values' in value) return (value as { values: string[] }).values.join(',')
127→    if ('latitude' in value && 'longitude' in value && 'radiusMiles' in value) {
128→      const g = value as { latitude: number; longitude: number; radiusMiles: number }
129→      return `${g.latitude},${g.longitude},${g.radiusMiles}`
130→    }
131→    if ('max' in value && !('min' in value))
132→      return String((value as { max: number }).max)
133→    if ('min' in value && !('max' in value))
134→      return String((value as { min: number }).min)
135→    if ('min' in value && 'max' in value) {
136→      const r = value as { min: number; max: number }
137→      return `${r.min},${r.max}`
138→    }
139→  }
140→  return String(value)
141→}
