package savedsearch

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
)

// SavedSearch represents a persisted search configuration.
type SavedSearch struct {
	ID          string
	Name        string
	Hash        string
	SearchState string
	Created     time.Time
	Updated     time.Time
}

// queryJSON is the JSONB wrapper stored in the query column.
type queryJSON struct {
	S string `json:"s"`
}

// Service manages saved searches in the ugc schema.
type Service struct {
	pool *pgxpool.Pool
}

// NewService returns a new saved-search service.
func NewService(pool *pgxpool.Pool) *Service {
	return &Service{pool: pool}
}

// TeamIDForUser looks up the team_id for a given user_id.
func (s *Service) TeamIDForUser(ctx context.Context, userID string) (string, error) {
	var teamID string
	err := s.pool.QueryRow(ctx,
		`SELECT team_id FROM subscription.team_member WHERE user_id = $1`, userID,
	).Scan(&teamID)
	if err != nil {
		return "", fmt.Errorf("savedsearch: team for user %s: %w", userID, err)
	}
	return teamID, nil
}

// List returns all saved searches for the given team, most recently updated first.
func (s *Service) List(ctx context.Context, teamID string) ([]SavedSearch, error) {
	rows, err := s.pool.Query(ctx, `
		SELECT id, name, hash, query, created, updated
		FROM ugc.saved_search
		WHERE team_id = $1
		ORDER BY updated DESC`, teamID)
	if err != nil {
		return nil, fmt.Errorf("savedsearch: list for team %s: %w", teamID, err)
	}
	defer rows.Close()

	var results []SavedSearch
	for rows.Next() {
		var ss SavedSearch
		var raw []byte
		if err := rows.Scan(&ss.ID, &ss.Name, &ss.Hash, &raw, &ss.Created, &ss.Updated); err != nil {
			return nil, fmt.Errorf("savedsearch: scan: %w", err)
		}
		var q queryJSON
		if err := json.Unmarshal(raw, &q); err != nil {
			return nil, fmt.Errorf("savedsearch: unmarshal query for %s: %w", ss.ID, err)
		}
		ss.SearchState = q.S
		results = append(results, ss)
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("savedsearch: rows: %w", err)
	}
	return results, nil
}

// Save creates a new saved search and returns it.
func (s *Service) Save(ctx context.Context, teamID, name, searchState string) (*SavedSearch, error) {
	hash := computeHash(searchState)
	q := queryJSON{S: searchState}
	data, err := json.Marshal(q)
	if err != nil {
		return nil, fmt.Errorf("savedsearch: marshal: %w", err)
	}

	var ss SavedSearch
	err = s.pool.QueryRow(ctx, `
		INSERT INTO ugc.saved_search (id, team_id, name, hash, query)
		VALUES (gen_random_uuid()::varchar(62), $1, $2, $3, $4)
		RETURNING id, name, hash, created, updated`,
		teamID, name, hash, data,
	).Scan(&ss.ID, &ss.Name, &ss.Hash, &ss.Created, &ss.Updated)
	if err != nil {
		return nil, fmt.Errorf("savedsearch: save for team %s: %w", teamID, err)
	}
	ss.SearchState = searchState
	return &ss, nil
}

// Delete removes a saved search by ID, scoped to the given team for authorization.
// Returns an error if the row does not exist or belongs to a different team.
func (s *Service) Delete(ctx context.Context, teamID, id string) error {
	tag, err := s.pool.Exec(ctx, `
		DELETE FROM ugc.saved_search
		WHERE id = $1 AND team_id = $2`, id, teamID)
	if err != nil {
		return fmt.Errorf("savedsearch: delete %s: %w", id, err)
	}
	if tag.RowsAffected() == 0 {
		return fmt.Errorf("savedsearch: delete %s: not found or not owned", id)
	}
	return nil
}

// computeHash returns the SHA-256 hex digest of a search state string.
func computeHash(searchState string) string {
	h := sha256.Sum256([]byte(searchState))
	return hex.EncodeToString(h[:])
}

