import { create } from 'zustand'
import { graphql } from 'gql.tada'
import { urqlClient } from '@/lib/urqlClient'

const PreferencesQuery = graphql(`
  query Preferences {
    preferences {
      homeLatitude
      homeLongitude
      homeState
    }
  }
`)

const UpdatePreferencesMutation = graphql(`
  mutation UpdatePreferences($input: UpdatePreferencesInput!) {
    updatePreferences(input: $input) {
      homeLatitude
      homeLongitude
      homeState
    }
  }
`)

interface PreferencesData {
  homeLatitude: number | null
  homeLongitude: number | null
  homeState: string | null
}

interface PreferencesState extends PreferencesData {
  loaded: boolean
  loading: boolean

  load: () => Promise<void>
  update: (prefs: Partial<PreferencesData>) => Promise<void>
  clear: () => void
}

export const usePreferencesStore = create<PreferencesState>()((set, get) => ({
  homeLatitude: null,
  homeLongitude: null,
  homeState: null,
  loaded: false,
  loading: false,

  load: async () => {
    if (get().loaded || get().loading) return
    set({ loading: true })
    try {
      const result = await urqlClient
        .query<{ preferences: PreferencesData }>(PreferencesQuery, {})
        .toPromise()
      if (result.data?.preferences) {
        const { homeLatitude, homeLongitude, homeState } = result.data.preferences
        set({
          homeLatitude: homeLatitude ?? null,
          homeLongitude: homeLongitude ?? null,
          homeState: homeState ?? null,
          loaded: true,
        })
      }
    } finally {
      set({ loading: false })
    }
  },

  update: async (prefs) => {
    const result = await urqlClient
      .mutation<{ updatePreferences: PreferencesData }>(UpdatePreferencesMutation, { input: prefs })
      .toPromise()
    if (result.data?.updatePreferences) {
      const { homeLatitude, homeLongitude, homeState } = result.data.updatePreferences
      set({
        homeLatitude: homeLatitude ?? null,
        homeLongitude: homeLongitude ?? null,
        homeState: homeState ?? null,
      })
    }
  },

  clear: () => {
    set({
      homeLatitude: null,
      homeLongitude: null,
      homeState: null,
      loaded: false,
      loading: false,
    })
  },
}))

import { Client, cacheExchange, fetchExchange } from 'urql'
import { authExchange } from '@urql/exchange-auth'
import { useAuthStore } from '@/stores/authStore'
import { supabase } from './supabase'

export const urqlClient = new Client({
  url: '/graphql',
  exchanges: [
    cacheExchange,
    authExchange(async (utils) => ({
      addAuthToOperation(operation) {
        const token = useAuthStore.getState().getToken()
        if (!token) return operation
        return utils.appendHeaders(operation, {
          Authorization: `Bearer ${token}`,
        })
      },
      didAuthError(error) {
        return error.graphQLErrors.some(
          (e) => e.extensions?.code === 'FORBIDDEN' || e.extensions?.code === 'UNAUTHENTICATED',
        ) || error.response?.status === 401
      },
      async refreshAuth() {
        const { data } = await supabase.auth.getSession()
        useAuthStore.getState().setSession(data.session)
      },
    })),
    fetchExchange,
  ],
})

