import { describe, it, expect, vi, beforeEach } from 'vitest'
import { renderWithMantine } from '@/test/render'
import { UserMenu } from './UserMenu'
import { useAuthStore } from '@/stores/authStore'
import userEvent from '@testing-library/user-event'

vi.mock('@/lib/supabase', () => ({
  supabase: {
    auth: {
      signOut: vi.fn().mockResolvedValue({}),
      getSession: vi.fn().mockResolvedValue({ data: { session: null } }),
      onAuthStateChange: vi.fn().mockReturnValue({ data: { subscription: { unsubscribe: vi.fn() } } }),
    },
  },
}))

beforeEach(() => {
  useAuthStore.setState({ user: null, session: null, loading: true })
})

const mockUser = {
  id: 'user-123',
  email: 'alice@example.com',
  user_metadata: { full_name: 'Alice Smith', avatar_url: 'https://example.com/a.jpg' },
  app_metadata: {},
  aud: 'authenticated',
  created_at: '',
} as never

describe('UserMenu', () => {
  it('renders nothing when no user', () => {
    useAuthStore.setState({ user: null, loading: false })
    const { queryByRole } = renderWithMantine(<UserMenu />)
    expect(queryByRole('img')).not.toBeInTheDocument()
  })

  it('renders avatar when user is present', () => {
    useAuthStore.setState({ user: mockUser, loading: false })
    const { container } = renderWithMantine(<UserMenu />)
    const avatar = container.querySelector('.mantine-Avatar-root')
    expect(avatar).toBeInTheDocument()
  })

  it('shows sign out option in dropdown', async () => {
    useAuthStore.setState({ user: mockUser, loading: false })
    const user = userEvent.setup()
    const { container, getByText } = renderWithMantine(<UserMenu />)
    const avatar = container.querySelector('.mantine-Avatar-root')
    expect(avatar).toBeTruthy()
    await user.click(avatar!.closest('[style*="cursor"]')!)
    expect(getByText(/sign out/i)).toBeInTheDocument()
  })
})

import { render, type RenderOptions } from '@testing-library/react'
import { AppProviders } from '../providers/AppProviders'

/** Wraps component in the production provider stack for tests that use Mantine components. */
export function renderWithMantine(ui: React.ReactElement, options?: RenderOptions) {
  return render(ui, {
    wrapper: ({ children }) => <AppProviders>{children}</AppProviders>,
    ...options,
  })
}

import { MantineProvider } from '@mantine/core'
import { theme } from '../theme'

/** Shared provider stack used by both production (main.tsx) and tests. */
export function AppProviders({ children }: { children: React.ReactNode }) {
  return <MantineProvider theme={theme}>{children}</MantineProvider>
}

