function setupMocks(
  fieldsOverride?: Record<string, unknown>,
  searchOverride?: Record<string, unknown>,
) {
  const fieldsState = {
    fetching: false,
    data: { searchFields: MOCK_FIELDS },
    error: undefined,
    ...fieldsOverride,
  }
  const searchState = {
    fetching: false,
    data: MOCK_SEARCH_DATA,
    error: undefined,
    ...searchOverride,
  }
  const outputFieldsState = {
    fetching: false,
    data: { searchOutputFields: MOCK_OUTPUT_FIELDS },
    error: undefined,
  }
  const detailState = {
    fetching: false,
    data: { institution: null },
    error: undefined,
  }
  const dataSourcesState = {
    fetching: false,
    data: { dataSources: [] },
    error: undefined,
  }
  mockUseQuery.mockImplementation((args: { query: unknown }) => {
    const opName = getOperationName(args.query)
    if (opName === 'SearchFields') {
      return [fieldsState, vi.fn()]
    }
    if (opName === 'SearchOutputFields') {
      return [outputFieldsState, vi.fn()]
    }
    if (opName === 'InstitutionDetail') {
      return [detailState, vi.fn()]
    }
    if (opName === 'DataSources') {
      return [dataSourcesState, vi.fn()]
    }
    return [searchState, vi.fn()]
  })
}

function renderSearch(initialEntry = '/search') {
  return render(
    <MemoryRouter initialEntries={[initialEntry]}>
      <AppProviders>
        <Search />
      </AppProviders>
    </MemoryRouter>,
  )
}

